arguments.file_text:
#:property AllowUnsafeBlocks=true

using System;

// Test stackalloc Span<nint>
Span<nint> nints = stackalloc nint[5];
for (int i = 0; i < nints.Length; i++)
    nints[i] = (nint)(i * 10);

Console.WriteLine($"Span<nint> length: {nints.Length}, element size: {sizeof(nint)} bytes");
for (int i = 0; i < nints.Length; i++)
    Console.WriteLine($"  nints[{i}] = {nints[i]}");

// Test stackalloc Span<nuint>
Span<nuint> nuints = stackalloc nuint[3];
for (int i = 0; i < nuints.Length; i++)
    nuints[i] = (nuint)(i + 100);

Console.WriteLine($"Span<nuint> length: {nuints.Length}, element size: {sizeof(nuint)} bytes");
for (int i = 0; i < nuints.Length; i++)
    Console.WriteLine($"  nuints[{i}] = {nuints[i]}");

Console.WriteLine("\nSuccess! stackalloc with nint/nuint works.");

